import React, { useMemo, useState, useCallback } from 'react';
import './DataTable.css';

const PAGE_SIZES = [10, 25, 50];

export default function DataTable({ data = [], columns = [] }) {
  const [sortKey, setSortKey]   = useState(null);
  const [sortDir, setSortDir]   = useState('asc');
  const [filter, setFilter]     = useState('');
  const [page, setPage]         = useState(0);
  const [pageSize, setPageSize] = useState(10);

  const cols = useMemo(() => columns.length ? columns : Object.keys(data[0] ?? {}), [data, columns]);

  const numericCols = useMemo(() => {
    const s = new Set();
    cols.forEach(c => { if (data.slice(0,20).every(r => r[c] === null || r[c] === undefined || typeof r[c] === 'number')) s.add(c); });
    return s;
  }, [data, cols]);

  const filtered = useMemo(() => {
    if (!filter.trim()) return data;
    const q = filter.toLowerCase();
    return data.filter(row => Object.values(row).some(v => String(v ?? '').toLowerCase().includes(q)));
  }, [data, filter]);

  const sorted = useMemo(() => {
    if (!sortKey) return filtered;
    return [...filtered].sort((a, b) => {
      const av = a[sortKey], bv = b[sortKey];
      const cmp = typeof av === 'number' && typeof bv === 'number' ? av - bv : String(av ?? '').localeCompare(String(bv ?? ''));
      return sortDir === 'asc' ? cmp : -cmp;
    });
  }, [filtered, sortKey, sortDir]);

  const totalPages = Math.ceil(sorted.length / pageSize);
  const pageRows   = sorted.slice(page * pageSize, (page + 1) * pageSize);

  const handleSort = useCallback((key) => {
    setSortKey(prev => { if (prev === key) setSortDir(d => d === 'asc' ? 'desc' : 'asc'); else setSortDir('asc'); return key; });
    setPage(0);
  }, []);

  const handleExport = useCallback(() => {
    const h = cols.join(',');
    const r = data.map(row => cols.map(c => JSON.stringify(row[c] ?? '')).join(',')).join('\n');
    const blob = new Blob([h + '\n' + r], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = 'flight_data.csv'; a.click();
    URL.revokeObjectURL(url);
  }, [data, cols]);

  const fmtVal = (v, col) => {
    if (v === null || v === undefined) return <span className="dt-null">—</span>;
    if (numericCols.has(col) && typeof v === 'number') return v.toLocaleString(undefined, { maximumFractionDigits: 2 });
    return String(v);
  };

  if (!data.length) return <p className="dt-empty">No data to display.</p>;

  return (
    <div className="dt-wrapper">
      <div className="dt-toolbar">
        <div className="dt-filter-wrap">
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#475569" strokeWidth="2"><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"/></svg>
          <input className="dt-filter" placeholder="Filter rows…" value={filter} onChange={e => { setFilter(e.target.value); setPage(0); }} />
          {filter && <button className="dt-clear" onClick={() => setFilter('')}>✕</button>}
        </div>
        <div className="dt-right">
          <span className="dt-count">{filtered.length.toLocaleString()} / {data.length.toLocaleString()} rows</span>
          <button className="dt-export" onClick={handleExport}>↓ CSV</button>
        </div>
      </div>

      <div className="dt-scroll">
        <table className="dt-table">
          <thead>
            <tr>
              <th className="dt-th dt-th-idx">#</th>
              {cols.map(col => (
  <th key={col} className={`dt-th ${sortKey === col ? 'sorted' : ''} ${numericCols.has(col) ? 'dt-th-num' : ''}`} onClick={() => handleSort(String(col))}>
    {String(col).replace(/_/g, ' ')} <span className="dt-sort-icon">{sortKey === col ? (sortDir === 'asc' ? '↑' : '↓') : '⇅'}</span>
  </th>
))}
            </tr>
          </thead>
          <tbody>
            {pageRows.map((row, ri) => (
              <tr key={ri} className="dt-tr">
                <td className="dt-td dt-td-idx">{page * pageSize + ri + 1}</td>
                {cols.map(col => (
                  <td key={col} className={`dt-td ${numericCols.has(col) ? 'dt-td-num' : ''}`}>{fmtVal(row[col], col)}</td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="dt-pagination">
          <div className="dt-page-sizes">
            <span className="dt-page-label">Rows:</span>
            {PAGE_SIZES.map(s => <button key={s} className={`dt-size-btn ${pageSize === s ? 'active' : ''}`} onClick={() => { setPageSize(s); setPage(0); }}>{s}</button>)}
          </div>
          <div className="dt-nav">
            <button className="dt-nav-btn" disabled={page === 0} onClick={() => setPage(0)}>«</button>
            <button className="dt-nav-btn" disabled={page === 0} onClick={() => setPage(p => p - 1)}>‹</button>
            <span className="dt-page-info">{page + 1} / {totalPages}</span>
            <button className="dt-nav-btn" disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>›</button>
            <button className="dt-nav-btn" disabled={page >= totalPages - 1} onClick={() => setPage(totalPages - 1)}>»</button>
          </div>
        </div>
      )}
    </div>
  );
}
